import flask
from werkzeug.security import safe_join
from werkzeug.exceptions import NotFound
import numpy as np

error404 = NotFound

def stack_and_save(arr_list: list[np.ndarray], base_path: str, sub_path: str, casting_policy: str, out_dtype: type) -> tuple[str, np.ndarray]:
    joined_path = safe_join(base_path, sub_path)
    if joined_path is None:
        raise error404()

    if casting_policy == 'safe':
        for arr in arr_list:
            if np.dtype(out_dtype).itemsize < arr.dtype.itemsize:
                raise TypeError(f"Cannot cast array of dtype {arr.dtype} to {out_dtype} with safe casting policy")
    elif casting_policy == 'unsafe':
        pass
    else:
        raise ValueError(f"Unknown casting policy: {casting_policy}")

    stacked = np.stack(arr_list, dtype=out_dtype)

    return joined_path, stacked

